type EditorialType = 'feature' | 'pro' | 'con' | 'pricing' | 'usecase';

export function getEditorialDescription(type: EditorialType, key: string, fallback: string): string {
    let registry: Record<string, string>;

    switch (type) {
        case 'feature':
            registry = FeatureDescriptions;
            break;
        case 'pro':
            registry = ProsDescriptions;
            break;
        case 'con':
            registry = ConsDescriptions;
            break;
        case 'pricing':
            registry = PricingDescriptions;
            break;
        case 'usecase':
            registry = UseCaseDescriptions;
            break;
        default:
            return fallback;
    }

    const description = registry[key];

    if (!description) {
        // Audit System: Log missing descriptions to the console so developers know to add them
        if (process.env.NODE_ENV === 'development') {
            console.warn(`[Editorial Audit] Missing unique description for ${type}: "${key}"`);
        }
        return fallback;
    }

    return description;
}
